class Solution {
    public int findMinimumOperations(String s1, String s2, String s3) {
        int operations = 0;
        while (!s1.equals(s2) || !s1.equals(s3)) {
            if (!s1.equals(s2)) {
                s1 = s1.substring(0, s1.length() - 1);
            }
            if (!s1.equals(s3)) {
                s3 = s3.substring(0, s3.length() - 1);
            }
            operations++;
        }
        return operations;
    }
}
